#!/usr/bin/env python3
"""
Generate Python code from JSON definitions.

This script reads JSON definitions and generates Python modules.
"""

import json
import subprocess
import sys
from pathlib import Path
from textwrap import dedent


def _format_with_ruff(path: Path) -> None:
    """Run ``ruff format`` on the generated file.

    Generated files are emitted with hand-rolled string concatenation, which
    does not match ``ruff format``'s canonical style (quote style, trailing
    commas, line wrapping). Without this post-write formatter pass, every
    regeneration re-introduces the same lint failures the CI ``lint-python``
    and ``pre-commit`` jobs check for (see issue #188).

    We invoke ``ruff`` via ``uv run`` so the project's pinned version is used.
    If ``uv``/``ruff`` is not on PATH (e.g., minimal CI image without uv),
    fall back to invoking ``ruff`` directly. If neither is available we warn
    but do not fail: regenerating must remain possible in odd environments,
    and the CI lint job will surface the formatting drift anyway.
    """
    for argv in (
        ["uv", "run", "ruff", "format", str(path)],
        ["ruff", "format", str(path)],
    ):
        try:
            subprocess.run(argv, check=True)
            return
        except FileNotFoundError:
            continue
        except subprocess.CalledProcessError as exc:
            print(f"⚠ ruff format failed on {path}: {exc}", file=sys.stderr)
            return
    print(
        f"⚠ ruff not found; skipping format of {path}. "
        "Install ruff (or uv) to keep generated output lint-clean.",
        file=sys.stderr,
    )


def generate_archetypes(json_path: Path, output_path: Path):
    """Generate archetypes.py from JSON."""
    with open(json_path) as f:
        data = json.load(f)

    archetypes = data["archetypes"]

    # Generate Python code
    code = dedent('''\
    """
    Agent archetypes - GENERATED FILE

    This file is automatically generated from definitions/archetypes.json
    DO NOT EDIT MANUALLY - changes will be overwritten

    To modify archetypes, edit definitions/archetypes.json and run:
        python scripts/generate_python.py
    """

    import numpy as np

    ''')

    # Generate individual archetype constants
    for name, spec in archetypes.items():
        constant_name = f"{name.upper()}_PARAMS"
        code += f"# {spec['description']}\n"
        code += f"{constant_name} = np.array([\n"
        for param in spec["params"]:
            code += f"    {param},\n"
        code += "], dtype=np.float32)\n\n"

    # Generate ARCHETYPES dictionary
    code += "\n# Registry of all archetypes\n"
    code += "ARCHETYPES = {\n"
    for name in archetypes.keys():
        constant_name = f"{name.upper()}_PARAMS"
        code += f'    "{name}": {constant_name},\n'
    code += "}\n"

    # Write output
    output_path.parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, "w") as f:
        f.write(code)

    # Re-format with ruff so the next CI run stays green (issue #188).
    _format_with_ruff(output_path)

    print(f"✓ Generated {output_path}")


def generate_scenarios(json_path: Path, output_path: Path):
    """Generate scenarios.py from JSON."""
    with open(json_path) as f:
        data = json.load(f)

    scenarios = data["scenarios"]

    # Generate Python code
    code = dedent('''\
    """
    Scenario definitions - GENERATED FILE

    This file is automatically generated from definitions/scenarios.json
    DO NOT EDIT MANUALLY - changes will be overwritten

    To modify scenarios, edit definitions/scenarios.json and run:
        python scripts/generate_python.py

    Parameter names match Rust implementation (bucket-brigade-core/src/scenarios.rs)
    """

    from dataclasses import dataclass, field
    from typing import List, Union
    import numpy as np


    @dataclass
    class Scenario:
        """Represents the stochastic configuration of a game.

        All parameter names match the Rust implementation for consistency.

        The four ownership reward fields (``reward_own_house_survives``,
        ``reward_other_house_survives``, ``penalty_own_house_burns``,
        ``penalty_other_house_burns``) are per-agent vectors of length
        ``num_agents`` (issue #198). Scalar inputs are auto-promoted to
        a length-``num_agents`` list of that value by ``__post_init__``
        for backward compatibility with existing scenario definitions.

        Issue #203 adds three optional spatial-cost fields:
        ``agent_home_positions`` (per-agent home position on the 10-ring,
        empty => fall back to the round-robin ``i % num_agents`` anchor),
        ``distance_cost_alpha`` (additive coefficient, ``0.0`` preserves
        pre-#203 behavior), and ``distance_metric`` (only ``"ring_arc"``
        is supported today).
        """

        # Fire dynamics
        prob_fire_spreads_to_neighbor: float  # Probability fire spreads to adjacent house
        prob_solo_agent_extinguishes_fire: float  # Probability one agent extinguishes fire
        prob_house_catches_fire: float  # Probability house catches fire each night

        # Team scoring (collective outcome)
        team_reward_house_survives: float  # Team reward for each house that survives
        team_penalty_house_burns: float  # Team penalty for each house that burns

        # Individual rewards (ownership-based, per-agent vectors of length num_agents)
        # Scalar inputs are auto-promoted in __post_init__ for backward compat.
        reward_own_house_survives: Union[float, List[float]]  # Per-agent reward when own house survives
        reward_other_house_survives: Union[float, List[float]]  # Per-agent reward when other house survives
        penalty_own_house_burns: Union[float, List[float]]  # Per-agent penalty when own house burns
        penalty_other_house_burns: Union[float, List[float]]  # Per-agent penalty when other house burns

        # Costs and structure
        cost_to_work_one_night: float  # Cost incurred when agent chooses to work
        min_nights: int  # Minimum nights before game can end

        # Game setup
        num_agents: int  # Number of agents participating

        # Spatial cost asymmetry (issue #203, optional, additive).
        # Empty ``agent_home_positions`` falls back to the round-robin
        # ``house_owners`` anchor (agent i -> house i). ``distance_cost_alpha
        # == 0.0`` (the implicit default for every pre-#203 scenario)
        # collapses the spatial term to zero, so existing scenarios are
        # bit-exactly unchanged.
        agent_home_positions: List[int] = field(default_factory=list)
        distance_cost_alpha: float = 0.0
        distance_metric: str = "ring_arc"

        # Topology (issue #254). Number of houses on the ring. Defaults to
        # 10 so all 14 pre-#254 scenarios (and any external JSON without the
        # field) remain bit-exact. New scenarios like ``v2_minimal`` set
        # this to a smaller value (2 in the v2 case). The Python env
        # wrappers read ``scenario.num_houses`` to size their action space
        # (``MultiDiscrete([num_houses, 2, 2])``) and observation arrays.
        num_houses: int = 10

        # Action-conditioned reward shaping (issue #259, optional, additive).
        # Both default to ``0.0`` so every pre-#259 scenario is bit-exactly
        # preserved (the env takes a fast-path skip when both knobs are zero).
        # ``action_shaping_alpha`` rewards workers who participated in
        # extinguishing a fire (BURNING -> SAFE this step), credit-shared
        # as ``alpha / workers_at_house``. ``action_shaping_beta`` is a flat
        # per-agent bonus for working at a SAFE house that stays SAFE
        # (preventive presence). REST actions never receive either bonus.
        # See ``bucket_brigade/envs/bucket_brigade_env.py::_compute_rewards``
        # and ``bucket-brigade-core/src/engine/rewards.rs`` for the canonical
        # implementation.
        action_shaping_alpha: float = 0.0
        action_shaping_beta: float = 0.0

        # Dense progress shaping (issue #265, optional, additive). Per-step
        # team-shared reward bonus proportional to the change in the number of
        # SAFE houses between the previous step and the current step:
        #
        #     team_reward += progress_shaping_coef * (cur_safe - prev_safe)
        #
        # Defaults to ``0.0`` so every pre-#265 scenario is bit-exactly
        # preserved (the env takes a fast-path skip when this knob is zero).
        # See ``bucket_brigade/envs/bucket_brigade_env.py::_compute_rewards``
        # and ``bucket-brigade-core/src/engine/rewards.rs`` for the canonical
        # implementation. Sequenced before potential-based shaping (#283) as
        # the cheap mechanical test of the dense-team-signal hypothesis.
        progress_shaping_coef: float = 0.0

        # Potential-based team-welfare shaping (issue #283, Ng-Harada-Russell 1999).
        # Default ``team_welfare_lambda == 0.0`` preserves bit-exact pre-#283
        # behavior (the env takes a fast-path skip when lambda is zero).
        #
        # When non-zero, an aligned per-step bonus ``F(s, a, s') = lambda * (
        # gamma * Phi(s') - Phi(s))`` is added to every agent's reward, shared
        # equally across the team. ``Phi(terminal) = 0`` is enforced exactly so
        # the telescoping sum identity holds:
        #     sum_t gamma^t F_t = lambda * (gamma^T Phi(s_T) - Phi(s_0))
        # which collapses to a constant ``-lambda * Phi(s_0)`` per episode when
        # ``Phi(s_T) == 0`` is enforced. NHR (ICML 1999) guarantees the optimal
        # policy set is preserved under this shaping for any potential ``Phi``.
        #
        # ``team_welfare_kind`` selects the potential function:
        #   - ``"none"``: shaping disabled (also implied when lambda == 0.0)
        #   - ``"team_welfare_closed_form"`` (option B from the issue):
        #         Phi(s) = team_reward * (safe/N) - team_penalty * (ruined/N)
        #                 - 0.5 * team_penalty * (burning/N)
        #     A cheap, debuggable closed-form proxy for team value. Coefficients
        #     are tied to the scenario's team-reward weights so the shaping
        #     signal stays on the same scale as the base reward.
        #
        # ``team_welfare_gamma`` is the NHR discount factor. It is **separate from**
        # the trainer's PPO discount (which is set in JointPPOTrainer) — the
        # theorem holds for *any* gamma applied in ``gamma * Phi(s') - Phi(s)``,
        # but invariance is strongest when this matches the trainer's gamma.
        # Default 1.0 keeps the shaping signal a simple delta when lambda is
        # turned on without a matching trainer discount setting.
        #
        # See ``bucket_brigade/envs/bucket_brigade_env.py::_compute_team_welfare_phi``
        # and ``bucket-brigade-core/src/engine/rewards.rs::team_welfare_phi`` for
        # the canonical implementations (kept in byte-parity).
        team_welfare_lambda: float = 0.0
        team_welfare_gamma: float = 1.0
        team_welfare_kind: str = "none"

        # Position-constrained action validity (issue #251, optional, opt-in).
        # Default ``"always_valid"`` preserves bit-exact pre-#251 behavior:
        # every house index in ``[0, num_houses)`` is a valid target for
        # every agent. Set to ``"adjacent_only"`` to constrain each agent
        # to acting at its home position (``agent_home_positions[i]``) or
        # a directly adjacent house (ring distance exactly 1).
        # Out-of-reach targets are sanitized to home by the env's ``step``
        # before any state mutation (the Python env mirrors the canonical
        # Rust implementation in ``bucket-brigade-core/src/engine/core.rs``).
        # k-hop and continuous-reach variants are deferred to follow-up issues.
        action_validity_mode: str = "always_valid"

        # Continuous extinguish dynamics (issue #253, option D from #234).
        # ``extinguish_mode`` selects the per-step extinguish dynamics:
        #   - ``"bernoulli"`` (default): pre-#253 per-step coin flip with
        #     ``P(extinguish) = 1 - (1-kappa)^k``. Fires that fail their roll
        #     burn out at end-of-step. Bit-exactly preserved for every
        #     pre-#253 scenario.
        #   - ``"continuous"``: damage-accumulation model. Each work step at
        #     a burning house adds ``suppression_per_worker * workers_here``
        #     to a per-house accumulator; fire transitions BURNING -> SAFE
        #     deterministically at threshold 1.0. Fires do NOT auto-burn-out
        #     in this mode (they persist across steps so the accumulator
        #     integrates suppression credit). The smoothing benefit option
        #     D targets comes from credit assignment via the value function.
        # See ``bucket_brigade/envs/bucket_brigade_env.py::_extinguish_fires``
        # and ``bucket-brigade-core/src/engine/phases.rs::extinguish_fires``
        # for the canonical implementations.
        extinguish_mode: str = "bernoulli"
        suppression_per_worker: float = 0.0

        # Within-night commitment mode (issue #252, option C from #234).
        # ``commitment_mode`` selects the per-night turn structure:
        #   - ``"simultaneous"`` (default): pre-#252 single-phase mechanic.
        #     Every agent emits ``[house, mode, signal]`` in a single
        #     round per night. Bit-exact backward compatibility.
        #   - ``"two_phase"``: C1 non-binding signaling. Each night becomes
        #     two micro-rounds at the trainer surface — round-1 emits a
        #     signal only (no movement, no cost, night does not advance),
        #     round-2 observes everyone's round-1 signal (in a new
        #     ``round1_signals`` obs channel) and emits a full
        #     ``[house, mode, signal]`` action. Round-2 mode is
        #     unconstrained by the round-1 signal — policies can emit
        #     ``signal=Work`` round-1 and ``mode=Rest`` round-2 (the
        #     deception channel survives).
        # The two-phase mechanic requires using
        # ``BucketBrigadeEnv.step_two_phase(round1_signals, round2_actions)``
        # instead of ``step``; calling ``step`` on a two-phase scenario
        # raises a clear error.
        commitment_mode: str = "simultaneous"

        def __post_init__(self) -> None:
            """Auto-promote scalar ownership reward fields to per-agent vectors.

            This is the canonical place where scalar -> list promotion happens
            for issue #198. Existing scenarios with scalar JSON values are
            still valid: a scalar ``v`` becomes ``[v] * num_agents``. Lists
            are validated to have exactly ``num_agents`` entries.

            Also validates the #203 spatial fields when present.
            """
            for fname in (
                "reward_own_house_survives",
                "reward_other_house_survives",
                "penalty_own_house_burns",
                "penalty_other_house_burns",
            ):
                value = getattr(self, fname)
                if isinstance(value, (int, float)):
                    setattr(self, fname, [float(value)] * self.num_agents)
                else:
                    # Already a sequence; coerce to list[float] and validate length.
                    promoted = [float(x) for x in value]
                    if len(promoted) != self.num_agents:
                        raise ValueError(
                            f"Scenario.{fname} has length {len(promoted)} "
                            f"but num_agents={self.num_agents}. Per-agent "
                            f"ownership reward vectors must match num_agents."
                        )
                    setattr(self, fname, promoted)

            # Issue #254 num_houses validation. Must be at least 2 for the
            # spread phase ring math to have distinct neighbors. Kept tight
            # to surface configuration mistakes early rather than blowing
            # up deep in a rollout.
            if self.num_houses < 2:
                raise ValueError(
                    f"Scenario.num_houses={self.num_houses} is too small; "
                    "must be at least 2."
                )

            # Issue #203 spatial-field validation.
            if self.agent_home_positions:
                positions = [int(p) for p in self.agent_home_positions]
                if len(positions) != self.num_agents:
                    raise ValueError(
                        f"Scenario.agent_home_positions has length "
                        f"{len(positions)} but num_agents={self.num_agents}. "
                        "Per-agent home position vectors must match num_agents."
                    )
                for i, p in enumerate(positions):
                    # Issue #254: range bound is now `num_houses`, not the
                    # hardcoded 10. Pre-#254 scenarios are unchanged because
                    # `num_houses` defaults to 10.
                    if not (0 <= p < self.num_houses):
                        raise ValueError(
                            f"Scenario.agent_home_positions[{i}]={p} "
                            f"is out of range [0, {self.num_houses})."
                        )
                self.agent_home_positions = positions
            # Keep in sync with the Rust allowlist in
            # `bucket-brigade-core/src/scenarios.rs::ALLOWED_DISTANCE_METRICS`.
            # Both sides reject unknown values to prevent silent ring-arc
            # fallback (issue #222 — `engine/rewards.rs` does not branch on
            # this field, so any unrecognized string would otherwise run
            # ring-arc geometry).
            if self.distance_metric != "ring_arc":
                raise ValueError(
                    f"Scenario.distance_metric={self.distance_metric!r} "
                    "is not supported; only 'ring_arc' is implemented today."
                )

            # Issue #283: potential-based team-welfare shaping allowlist.
            # Keep in sync with the Rust validator in
            # ``bucket-brigade-core/src/scenarios.rs::ALLOWED_TEAM_WELFARE_KINDS``.
            # ``"none"`` is the default and means shaping is disabled even if
            # lambda is non-zero (the env shortcuts on kind="none").
            allowed_team_welfare_kinds = ("none", "team_welfare_closed_form")
            if self.team_welfare_kind not in allowed_team_welfare_kinds:
                raise ValueError(
                    f"Scenario.team_welfare_kind={self.team_welfare_kind!r} "
                    f"is not supported; allowed values: {allowed_team_welfare_kinds!r}."
                )

            # Issue #251: action_validity_mode allowlist. Keep in sync with
            # the Rust allowlist in
            # ``bucket-brigade-core/src/scenarios.rs::ALLOWED_ACTION_VALIDITY_MODES``.
            # ``"always_valid"`` (default) preserves bit-exact pre-#251 behavior;
            # ``"adjacent_only"`` enables the v1 position-constrained mask.
            allowed_action_validity_modes = ("always_valid", "adjacent_only")
            if self.action_validity_mode not in allowed_action_validity_modes:
                raise ValueError(
                    f"Scenario.action_validity_mode={self.action_validity_mode!r} "
                    f"is not supported; allowed values: {allowed_action_validity_modes!r}."
                )

            # Issue #253: extinguish_mode allowlist. Keep in sync with the
            # Rust validator in
            # ``bucket-brigade-core/src/scenarios.rs::ALLOWED_EXTINGUISH_MODES``.
            # ``"bernoulli"`` is the default and preserves pre-#253
            # behavior bit-exactly.
            allowed_extinguish_modes = ("bernoulli", "continuous")
            if self.extinguish_mode not in allowed_extinguish_modes:
                raise ValueError(
                    f"Scenario.extinguish_mode={self.extinguish_mode!r} "
                    f"is not supported; allowed values: {allowed_extinguish_modes!r}."
                )

            # Issue #252: commitment_mode allowlist. Keep in sync with the
            # Rust validator in
            # ``bucket-brigade-core/src/scenarios.rs::ALLOWED_COMMITMENT_MODES``.
            # ``"simultaneous"`` is the default and preserves pre-#252
            # single-phase behavior bit-exactly. ``"two_phase"`` invokes
            # the C1 non-binding signaling mechanic; callers must use
            # ``BucketBrigadeEnv.step_two_phase`` instead of ``step``.
            allowed_commitment_modes = ("simultaneous", "two_phase")
            if self.commitment_mode not in allowed_commitment_modes:
                raise ValueError(
                    f"Scenario.commitment_mode={self.commitment_mode!r} "
                    f"is not supported; allowed values: {allowed_commitment_modes!r}."
                )

        def to_feature_vector(self) -> np.ndarray:
            """
            Convert scenario parameters to a feature vector for agent conditioning.

            Returns a numpy array with scenario features. The four per-agent
            ownership reward fields are reduced to their mean across agents
            so the feature vector retains its 12-element layout (#198). For
            scenarios with uniform per-agent weights (the legacy scalar-promoted
            case) the mean equals the original scalar value, preserving
            backward compatibility.
            """
            return np.array(
                [
                    self.prob_fire_spreads_to_neighbor,
                    self.prob_solo_agent_extinguishes_fire,
                    self.prob_house_catches_fire,
                    self.team_reward_house_survives,
                    self.team_penalty_house_burns,
                    float(np.mean(self.reward_own_house_survives)),
                    float(np.mean(self.reward_other_house_survives)),
                    float(np.mean(self.penalty_own_house_burns)),
                    float(np.mean(self.penalty_other_house_burns)),
                    self.cost_to_work_one_night,
                    self.min_nights,
                    self.num_agents,
                ],
                dtype=np.float32,
            )


    ''')

    # Generate factory functions
    # Ownership reward fields are emitted as the literal value from JSON --
    # scalar or list. The Scenario dataclass __post_init__ auto-promotes
    # scalars to length-num_agents vectors (issue #198).
    def _emit_value(v):
        # Emit Python literal for either a scalar or a list of scalars.
        if isinstance(v, list):
            return "[" + ", ".join(repr(float(x)) for x in v) + "]"
        return repr(v)

    for name, spec in scenarios.items():
        function_name = f"{name}_scenario"
        code += f"def {function_name}(num_agents: int) -> Scenario:\n"
        code += f'    """{spec["description"]}"""\n'
        code += "    return Scenario(\n"
        code += f"        prob_fire_spreads_to_neighbor={spec['prob_fire_spreads_to_neighbor']},\n"
        code += f"        prob_solo_agent_extinguishes_fire={spec['prob_solo_agent_extinguishes_fire']},\n"
        code += f"        prob_house_catches_fire={spec['prob_house_catches_fire']},\n"
        code += f"        team_reward_house_survives={spec['team_reward_house_survives']},\n"
        code += (
            f"        team_penalty_house_burns={spec['team_penalty_house_burns']},\n"
        )
        code += f"        reward_own_house_survives={_emit_value(spec['reward_own_house_survives'])},\n"
        code += f"        reward_other_house_survives={_emit_value(spec['reward_other_house_survives'])},\n"
        code += f"        penalty_own_house_burns={_emit_value(spec['penalty_own_house_burns'])},\n"
        code += f"        penalty_other_house_burns={_emit_value(spec['penalty_other_house_burns'])},\n"
        code += f"        cost_to_work_one_night={spec['cost_to_work_one_night']},\n"
        code += f"        min_nights={spec['min_nights']},\n"
        code += "        num_agents=num_agents,\n"
        # Issue #203 optional spatial-cost fields. Emit only when set in JSON
        # (every other scenario keeps the dataclass defaults: empty list,
        # alpha=0.0, metric="ring_arc") so behavior is byte-identical to
        # pre-#203 codegen output for those scenarios.
        if "agent_home_positions" in spec:
            code += f"        agent_home_positions={list(spec['agent_home_positions'])!r},\n"
        if "distance_cost_alpha" in spec:
            code += f"        distance_cost_alpha={spec['distance_cost_alpha']},\n"
        if "distance_metric" in spec:
            code += f"        distance_metric={spec['distance_metric']!r},\n"
        # Issue #254 optional num_houses field. Emit only when explicitly
        # set in JSON so every pre-#254 scenario factory is byte-identical
        # to pre-#254 codegen output (they all keep the dataclass default
        # of 10).
        if "num_houses" in spec:
            code += f"        num_houses={spec['num_houses']},\n"
        # Issue #259 optional action-shaping fields. Emit only when set in
        # JSON so every pre-#259 scenario factory is byte-identical to
        # pre-#259 codegen output (they all keep the dataclass defaults
        # of 0.0).
        if "action_shaping_alpha" in spec:
            code += f"        action_shaping_alpha={spec['action_shaping_alpha']},\n"
        if "action_shaping_beta" in spec:
            code += f"        action_shaping_beta={spec['action_shaping_beta']},\n"
        # Issue #265 optional dense progress shaping field. Emit only when set
        # in JSON so every pre-#265 scenario factory is byte-identical to
        # pre-#265 codegen output (they all keep the dataclass default of 0.0).
        if "progress_shaping_coef" in spec:
            code += f"        progress_shaping_coef={spec['progress_shaping_coef']},\n"
        # Issue #283 optional potential-based shaping fields. Emit only when
        # set in JSON so every pre-#283 scenario factory is byte-identical
        # to pre-#283 codegen output (they keep the dataclass defaults:
        # lambda=0.0, gamma=1.0, kind="none").
        if "team_welfare_lambda" in spec:
            code += f"        team_welfare_lambda={spec['team_welfare_lambda']},\n"
        if "team_welfare_gamma" in spec:
            code += f"        team_welfare_gamma={spec['team_welfare_gamma']},\n"
        if "team_welfare_kind" in spec:
            code += f"        team_welfare_kind={spec['team_welfare_kind']!r},\n"
        # Issue #251 optional position-constrained action validity. Emit only
        # when set in JSON so every pre-#251 scenario factory is byte-identical
        # to pre-#251 codegen output (they keep the dataclass default
        # "always_valid").
        if "action_validity_mode" in spec:
            code += f"        action_validity_mode={spec['action_validity_mode']!r},\n"
        # Issue #253 optional continuous-extinguish fields. Emit only when
        # set in JSON so every pre-#253 scenario factory is byte-identical
        # to pre-#253 codegen output (they keep the dataclass defaults:
        # mode="bernoulli", suppression=0.0).
        if "extinguish_mode" in spec:
            code += f"        extinguish_mode={spec['extinguish_mode']!r},\n"
        if "suppression_per_worker" in spec:
            code += (
                f"        suppression_per_worker={spec['suppression_per_worker']},\n"
            )
        # Issue #252 optional within-night commitment mode. Emit only when
        # set in JSON so every pre-#252 scenario factory is byte-identical
        # to pre-#252 codegen output (they keep the dataclass default
        # "simultaneous").
        if "commitment_mode" in spec:
            code += f"        commitment_mode={spec['commitment_mode']!r},\n"
        code += "    )\n\n\n"

    # Generate SCENARIO_REGISTRY
    code += "\n# Registry of all scenarios\n"
    code += "SCENARIO_REGISTRY = {\n"
    for name in scenarios.keys():
        function_name = f"{name}_scenario"
        code += f'    "{name}": {function_name},\n'
    code += "}\n\n\n"

    # Generate helper functions
    code += dedent('''
    def get_scenario_by_name(name: str, num_agents: int) -> Scenario:
        """
        Get a scenario by name.

        Args:
            name: Scenario name (e.g., "trivial_cooperation", "default")
            num_agents: Number of agents in the scenario

        Returns:
            Scenario object

        Raises:
            ValueError: If scenario name is invalid

        Example:
            >>> scenario = get_scenario_by_name("trivial_cooperation", num_agents=4)
        """
        if name not in SCENARIO_REGISTRY:
            valid_names = ", ".join(sorted(SCENARIO_REGISTRY.keys()))
            raise ValueError(f"Unknown scenario '{name}'. Valid options: {valid_names}")

        return SCENARIO_REGISTRY[name](num_agents)


    def list_scenarios() -> list:
        """
        Get list of available scenario names.

        Returns:
            Sorted list of scenario names

        Example:
            >>> scenarios = list_scenarios()
            >>> print(scenarios)
            ['chain_reaction', 'deceptive_calm', 'default', ...]
        """
        return sorted(SCENARIO_REGISTRY.keys())
    ''')

    # Write output
    output_path.parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, "w") as f:
        f.write(code)

    # Re-format with ruff so the next CI run stays green (issue #188).
    _format_with_ruff(output_path)

    print(f"✓ Generated {output_path}")


def main():
    """Generate all Python modules from JSON."""
    root = Path(__file__).parent.parent
    definitions_dir = root / "definitions"

    generate_archetypes(
        definitions_dir / "archetypes.json",
        root / "bucket_brigade" / "agents" / "archetypes_generated.py",
    )

    generate_scenarios(
        definitions_dir / "scenarios.json",
        root / "bucket_brigade" / "envs" / "scenarios_generated.py",
    )

    print("\n✓ Python code generation complete!")


if __name__ == "__main__":
    main()
